const SCALE_FLAME = 2 / 3;
const SCALE_GLOBAL = 4;

async function main() {
	const browser = await puppeteer.launch({
		headless: true,
		args: ["--no-sandbox", "--disable-setuid-sandbox"],
	});
	const page = await browser.newPage();
	await page.goto("about:blank", { waitUntil: "domcontentloaded" });
	await page.addScriptTag({
		url: "https://cdnjs.cloudflare.com/ajax/libs/paper.js/0.12.18/paper-full.min.js",
	});

	const svg = await page.evaluate(
		({ path1, paths2, scaleFlame, scaleGlobal }) => {
			const canvas = document.createElement("canvas");
			canvas.width = 2400;
			canvas.height = 2400;
			paper.setup(canvas);

			// 複合 path は Paper の splitAt が破綻するため、弧長最大のサブパスだけを4分割する
			const subparts = path1.match(/[Mm][^Mm]*/g) || [];
			const ns = "http://www.w3.org/2000/svg";
			const tmpSvg = document.createElementNS(ns, "svg");
			const tmpPath = document.createElementNS(ns, "path");
			tmpSvg.appendChild(tmpPath);
			document.body.appendChild(tmpSvg);
			let mainD = subparts[0] || path1;
			let maxLen = 0;
			for (const d of subparts) {
				tmpPath.setAttribute("d", d);
				const len = tmpPath.getTotalLength();
				if (len > maxLen) {
					maxLen = len;
					mainD = d;
				}
			}
			document.body.removeChild(tmpSvg);

			const full = new paper.Path(mainD);
			if (!full.length) {
				throw new Error("Main subpath length is zero");
			}
			const q = full.length / 4;
			const tail1 = full.splitAt(full.getLocationAt(q));
			const tail2 = tail1.splitAt(tail1.getLocationAt(q));
			const tail3 = tail2.splitAt(tail2.getLocationAt(q));
			const q1 = full;
			const q2 = tail1;
			const q3 = tail2;
			const q4 = tail3;

			const textGroup = new paper.Group();
			paths2.forEach((d) => {
				textGroup.addChild(new paper.Path(d));
			});

			const flameGroup = new paper.Group();
			flameGroup.addChild(q1);
			flameGroup.addChild(q2);
			flameGroup.addChild(q3);
			flameGroup.addChild(q4);
			for (const d of subparts) {
				if (d !== mainD) {
					flameGroup.addChild(new paper.Path(d));
				}
			}

			const centerText = textGroup.bounds.center;
			flameGroup.scale(scaleFlame, flameGroup.bounds.center);
			flameGroup.translate(centerText.subtract(flameGroup.bounds.center));

			const root = new paper.Group();
			root.addChild(textGroup);
			root.addChild(flameGroup);
			root.scale(scaleGlobal, new paper.Point(0, 0));

			const bb = root.bounds;
			const x = bb.x;
			const y = bb.y;
			const w = bb.width;
			const h = bb.height;

			return paper.project.exportSVG({
				bounds: new paper.Rectangle(x, y, w, h),
				asString: true,
				precision: 5,
			});
		},
		{
			path1: PATH1,
			paths2: PATHS2,
			scaleFlame: SCALE_FLAME,
			scaleGlobal: SCALE_GLOBAL,
		},
	);

	await browser.close();
	process.stdout.write(svg);
}

main().catch((err) => {
	console.error(err);
	process.exit(1);
});
